#include <batteries/bit_ops/index_of.hpp>

#include <benchmark/benchmark.h>

#include <batteries/assert.hpp>

#ifdef __BMI2__
#include <x86gprintrin.h>
#endif  // __BMI2__

#ifdef __MMX__
#include <mmintrin.h>
#endif  // __MMX__

#ifdef __SSE2__
#include <emmintrin.h>
#endif  // __SSE2__

#ifdef __SSE3__
#include <pmmintrin.h>
#endif  // __SSE3__

#ifdef __AVX__
#include <immintrin.h>
#endif

#ifdef __AVX512F__
#include <immintrin.h>  // AVX512 (AVX, AVX2, FMA)
#endif

namespace {

using namespace batt::int_types;

namespace diy {

inline usize index_of(i8 key_byte, const std::array<i8, 4>& keys)
{
#ifdef __MMX__

    __m64 pattern = _mm_set1_pi8(key_byte);
    u64 extended = *((const u32*)keys.data());
    __m64 values = _mm_cvtsi64_m64(extended);
    __m64 result = _m_pcmpeqb(pattern, values);

    return ((__builtin_ffsll((i64)result) - 1) >> 3) & 7;

#else
    return ::batt::slow_index_of(key_byte, keys);
#endif  // __MMX__
}

BATT_ALWAYS_INLINE inline usize index_of(u8 key_byte, const std::array<u8, 4>& keys)
{
    return index_of(static_cast<i8>(key_byte), reinterpret_cast<const std::array<i8, 4>&>(keys));
}

inline usize index_of(u8 key_byte, const std::array<u8, 8>& keys)
{
#ifdef __MMX__

    __m64 pattern = _mm_set1_pi8((char)key_byte);
    u64 extended = *((const u64*)keys.data());
    __m64 values = _mm_cvtsi64_m64(extended);
    __m64 result = _m_pcmpeqb(pattern, values);

    return ((__builtin_ffsll((i64)result) - 1) >> 3) & 15;

#else
    return ::batt::slow_index_of(key_byte, keys);
#endif  // __MMX__
}

inline usize index_of(u8 key_byte, const std::array<u8, 16>& keys)
{
#if defined(__SSE2__) && defined(__SSE3__)
    __m128i pattern = _mm_set1_epi8((char)key_byte);
    __m128i values = _mm_lddqu_si128((const __m128i*)keys.data());

#if defined(__AVX512F__)
    __mmask16 result = _mm_cmpeq_epi8_mask(pattern, values);
#else
    int result = _mm_movemask_epi8(_mm_cmpeq_epi8(pattern, values));
#endif

    return (__builtin_ffs(result) - 1) & 31;

#else
    return ::batt::slow_index_of(key_byte, keys);
#endif
}

inline usize index_of(u8 key_byte, const std::array<u8, 32>& keys)
{
#if defined(__AVX__)
    __m256i pattern = _mm256_set1_epi8((char)key_byte);
    __m256i values = _mm256_lddqu_si256((const __m256i*)keys.data());

#if defined(__AVX512F__)
    __mmask32 result = _mm256_cmpeq_epi8_mask(pattern, values);
#else
    int result = _mm256_movemask_epi8(_mm256_cmpeq_epi8(pattern, values));
#endif

    return (__builtin_ffs(result) - 1) & 63;

#else
    return ::batt::slow_index_of(key_byte, keys);
#endif
}

inline usize index_of(u8 key_byte, const std::array<u8, 64>& keys)
{
#if defined(__AVX512F__)

    __m512i pattern = _mm512_set1_epi8((char)key_byte);
    __m512i values = _mm512_loadu_si512((const __m512i*)keys.data());

    __mmask64 result = _mm512_cmpeq_epi8_mask(pattern, values);

    return (__builtin_ffsll(result) - 1) & 127;

#else
    return ::batt::slow_index_of(key_byte, keys);
#endif
}

}  //namespace diy

constexpr u64 kPrime = 7829;

template <typename T, usize N, bool kDiy>
void Benchmark_IndexOf_Impl(benchmark::State& state)
{
    for (auto _ : state) {
        std::array<T, N> val;
        static_assert(sizeof(val) >= 4);
        usize total = 0;
        for (usize i = 0; i < state.range(0); ++i) {
            total += kDiy ? diy::index_of(T{99}, val) : batt::index_of(T{99}, val);
            *(u32*)(val.data() + (i & (sizeof(val) / 4 - 1))) += kPrime;
        }
        BATT_CHECK_NE(total, 0);
    }
}

void Benchmark_IndexOf4(benchmark::State& state)
{
    Benchmark_IndexOf_Impl<u8, 4, false>(state);
}

void Benchmark_IndexOf4_Diy(benchmark::State& state)
{
    Benchmark_IndexOf_Impl<u8, 4, true>(state);
}

